        let batch = std::mem::take(&mut session.code_out.last_files_written);
        modified += undo_batch(&batch, &t, &mut dirs_to_clean);

        // Undo additional batches from stack
        for _ in 1..levels {
            if let Some(batch) = session.code_out.undo_stack.pop() {
                modified += undo_batch(&batch, &t, &mut dirs_to_clean);
            }
