    session.history_mgr.clear_turns();
    session.last_search.clear();
    session.last_tokens = 0;
    let rail = ui::theme::paint_rail_empty(&t);
    let msg = ui::theme::paint_success_label(&t, "conversation cleared");
    println!("{rail}");
    println!("{rail} {msg}");
    println!("{rail}");
}

