                    }
                    let step = remaining.min(poll_interval);
                    sleep(step).await;
                    remaining = remaining.saturating_sub(step);
                }
            }
        }
    }
    Err(last_err.unwrap_or_else(|| anyhow!(ProviderError::Other("retry exhausted".into()))))
