//! Live file watcher for auto re-indexing.
//! Watches the project directory for file create/modify/delete events,
//! debounces them (batches within 1 second), and triggers index regeneration.
//!
//! These functions are ready for CLI integration (e.g., via a `/watch` REPL command).

use std::path::Path;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::mpsc;
use std::sync::Arc;
use std::time::Duration;

use anyhow::Result;
use notify::{Config, Event, RecommendedWatcher, RecursiveMode, Watcher};
use tracing::warn;

/// Creates a `RecommendedWatcher` with up to 3 retry attempts and exponential backoff.
/// Logs errors and returns `None` if all attempts fail.
fn create_watcher_with_retry(tx: &mpsc::Sender<()>, event_tx: &mpsc::Sender<Vec<Event>>) -> Option<RecommendedWatcher> {
    for attempt in 1..=3 {
        let tx_clone = event_tx.clone();
        match RecommendedWatcher::new(
            move |res: Result<Event, notify::Error>| match res {
                Ok(event) => {
                    let _ = tx_clone.send(vec![event]);
                }
                Err(e) => warn!("notify watch error: {}", e),
            },
            Config::default(),
        ) {
            Ok(w) => return Some(w),
            Err(e) => {
                warn!("failed to create file watcher (attempt {}/3): {}", attempt, e);
                if attempt < 3 {
                    std::thread::sleep(Duration::from_millis(500 * attempt));
                }
            }
        }
    }
    let _ = tx; // suppress unused warning — sender stays alive for the caller
    None
}

